package com.cognizant.inventory.model;import jakarta.persistence.*;@Entity public class Inventory {@Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id;private Long productId;private Integer stock; public Long getId(){return id;} public void setId(Long id){this.id=id;} public Long getProductid(){return productId;} public void setProductid(Long productId){this.productId=productId;}public Integer getStock(){return stock;} public void setStock(Integer stock){this.stock=stock;}}